import React from 'react'
import ReactApexChart from 'react-apexcharts'
import ApexCharts from 'apexcharts'
import './styles.css'

// Cadence: a custom named easing, registered before the chart is created.
// A springy overshoot-and-settle bounce.
ApexCharts.registerEasing('bounce', function (t) {
  var c4 = (2 * Math.PI) / 3
  if (t === 0 || t === 1) return t
  return Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1
})

function shuffledData() {
  var out = []
  for (var i = 0; i < 8; i++) out.push(20 + Math.round(Math.random() * 80))
  return out
}

// A bracketed value is a cubic-bezier array; otherwise a registered name.
// Shared by the vanilla-js, React and Vue builds.
function parseEase(raw) {
  if (raw.charAt(0) === '[') {
    try {
      return JSON.parse(raw)
    } catch (e) {
      return raw
    }
  }
  return raw
}

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [{ name: 'Value', data: [42, 68, 35, 80, 55, 24, 71, 60] }],
    options: {
      chart: {
        id: 'cadenceChart',
        height: 400,
        type: 'bar',
        fontFamily: 'Helvetica, Arial, sans-serif',
        toolbar: { show: false },
        animations: {
          enabled: true,
          speed: 900,
          easing: 'easeInOutSine',
          // The Shuffle button changes data, so the tween you watch is the
          // data-update (dynamicAnimation) one. Slow it down so the easing curve is
          // easy to read; chart.animations.speed above governs the initial draw.
          dynamicAnimation: {
            enabled: true,
            speed: 900,
          },
          animateGradually: {
            enabled: false,
          },
        },
      },
      colors: ['#14b8a6'],
      plotOptions: { bar: { columnWidth: '55%', borderRadius: 4 } },
      dataLabels: { enabled: false },
      title: { text: 'Data-update tween easing', align: 'left' },
      xaxis: {
        categories: ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H'],
      },
      yaxis: { min: 0, max: 100 },
    },
  })

  React.useEffect(() => {
    // The react-apexcharts wrapper owns the render, so reach the live instance by
    // its chart.id, then wire the same controls the vanilla build does.
    // (parseEase and shuffledData live in the shared head script.) updateOptions /
    // updateSeries drive the chart instance directly, so no React state changes.
    let chart
    const timer = window.setInterval(() => {
      chart = ApexCharts.getChartByID('cadenceChart')
      if (!chart) return
      window.clearInterval(timer)

      const buttons = Array.prototype.slice.call(
        document.querySelectorAll('.controls button[data-ease]'),
      )
      buttons.forEach((btn) => {
        btn.addEventListener('click', () => {
          buttons.forEach((b) => b.classList.remove('active'))
          btn.classList.add('active')
          const currentEasing = parseEase(btn.getAttribute('data-ease'))
          chart.updateOptions({
            chart: { animations: { easing: currentEasing } },
          })
        })
      })

      document.getElementById('shuffle').addEventListener('click', () => {
        chart.updateSeries([{ name: 'Value', data: shuffledData() }])
      })
    }, 50)

    return () => window.clearInterval(timer)
  }, [])

  return (
    <div>
      <div className="panel">
        <div className="controls">
          <span className="label">Easing:</span>
          <button data-ease="easeInOutSine" className="active">
            easeInOutSine (default)
          </button>
          <button data-ease="linear">linear</button>
          <button data-ease="easeOutBack">easeOutBack</button>
          <button data-ease="bounce">bounce (custom)</button>
          <button data-ease="[0.34,1.56,0.64,1]">cubic-bezier</button>
          <button className="shuffle" id="shuffle">
            Shuffle data
          </button>
        </div>
      </div>

      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="bar"
          height={400}
        />
      </div>

      <div className="panel">
        <div className="note">
          Pick an easing, then <b>Shuffle data</b> to watch the bars tween to
          their new heights with that curve. Set it via
          <code>chart.animations.easing</code>: a registered name (
          <code>'easeOutBack'</code>), a cubic-bezier
          <code>[0.34, 1.56, 0.64, 1]</code>, or a function. Register your own
          with
          <code>ApexCharts.registerEasing('bounce', fn)</code>. The default,
          <code>'easeInOutSine'</code>, is the historical curve, so existing
          charts animate exactly as before. Easing governs the data-update
          tweens whose tempo is <code>dynamicAnimation.speed</code> (set to
          900ms here so the curve reads clearly); the tuned initial-draw pen and
          pop animations keep their own feel.
        </div>
      </div>
    </div>
  )
}

export default ApexChart

#chart {
  max-width: 820px;
  margin: 12px auto 4px;
}
.panel {
  max-width: 820px;
  margin: 14px auto;
  font-family: sans-serif;
