  padding: 6px 12px;
  cursor: pointer;
  border: 1px solid #d3d8e3;
  background: #fff;
  border-radius: 6px;
  font-size: 13px;
}
.controls button.active {
  border-color: #14b8a6;
  color: #0f766e;
  background: #f0fdfa;
  font-weight: 600;
}
